var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하아아…","JPN":"はああ……","ENG":"*Sigh...*","TWN":"唉啊啊……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"여기에 갇힌 뒤로 시간이 대체 얼마나 지난 거람?","JPN":"ここに閉じ込められて、もうどれくらい？","ENG":"How long has it been since we were locked up here?","TWN":"我被困在這裡有多久了？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"범인이 누군지도 모른다면서 우리만 이렇게 붙잡아 두는 게 말이 돼?","JPN":"犯人が誰なのかもわからないのに、私たちだけ拘束するなんて、ひどくない？","ENG":"They don't even know who did it. They can't lock us in here like this.","TWN":"你連兇手是誰都不清楚就把我關在這裡？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"다들 우리가 여기에 갇혀있는지도 모르고 있을 텐데.","JPN":"みんなは私たちがここに閉じ込められてることも知らないんだろうな。","ENG":"I bet no one even knows we're stuck here.","TWN":"大家可能並不知道我們被關在這裡。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국 시니어의 살해현장에 있었으니, 보안을 위해 필요한 격리조치라고 봐야겠지.","JPN":"管理局シニアの殺人現場にいたのだから、保安のため必要な隔離措置だと考えるべきだろう。","ENG":"Since we were at the scene of an Administration Senior's murder, it was probably necessary to separate us for security reasons.","TWN":"管理局Senior被殺害時我們就在現場，應該是基於安全的理由採取了隔離措施吧。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 적어도 사장님은 내보내 줘야 하는 거 아냐? 관리국에서 제일 높은 사람이 자기 부하를 해칠 이유가 어딨냐고.","JPN":"なら、少なくとも社長は出してもらわないとダメじゃない？　管理局で一番偉い人が自分の部下を殺すはずないし。","ENG":"If that's the case, shouldn't they at least let you free, Boss? Why would the head of the Administration harm people under him?","TWN":"那麼至少應該放老闆走吧？管理局最高負責人怎麼可能會殺害自己的部下。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"표면상으론 나도 암살자에게 당하지 않도록 보호를 받고 있는 것이네만.","JPN":"表面上、私も暗殺されないよう保護されているわけなのだが。","ENG":"On the surface, I'm also under protection against any assassination attempts.","TWN":"表面上看來，我也算是有受到保護以免被殺手殺害。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리자 권한을 박탈 당한 입장이니, 의심을 받는 것도 이상하지는 않지.","JPN":"管理者の権限を剥奪された立場なのだから、疑われるのも仕方ない。","ENG":"However, it wouldn't be weird for them to suspect me since I lost my authority as the Administrator.","TWN":"畢竟被剝奪了管理者權限，因此受到懷疑也就不足為奇了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"지금 현장을 통솔하고 있는 사람이 우리 회사가 있던 곳 시니어라며?","JPN":"今現場を率いている人が、私たちの会社があったところのシニアだって言ってたでしょ？","ENG":"Isn't the person in charge of the case the Senior of where our company building was?","TWN":"聽說目前指揮現場的人是我們公司所在地區的Senior？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 사람이 사장님을 만난 적 있다거나, 개인적으로 싫어하는 건 아니겠지?","JPN":"その人が社長と知り合いだったとか、個人的に嫌われてるとかじゃないの？","ENG":"Has the person ever met you? Or have a reason to hate you?","TWN":"那個人是不是見過老闆？或者和老闆有私人恩怨吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니라고… 장담은 못하겠군.","JPN":"……否定はできないな。","ENG":"I can't say... that's not true.","TWN":"這個……我不確定。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"그라운드 원 시니어님께서 최고 관리자님을 호출하셨습니다.","JPN":"グラウンド・ワンのシニアが最高管理者さんをお呼びです。","ENG":"The Senior of Ground One has asked for your presence, Supreme Administrator.","TWN":"G1 Senior呼叫最高管理者。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"직접 대면해 나눌 얘기가 있으시다는군요.","JPN":"直接会って、話したいことがあるそうです。","ENG":"She would like to speak to you in person.","TWN":"說是有些話要見面聊。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리로 안내해주게.","JPN":"そちらに案内してくれたまえ。","ENG":"Lead the way.","TWN":"帶我去。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기… 나는?","JPN":"あの……私は？","ENG":"Uh... What about me?","TWN":"那……我呢？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"다른 용의자 분은 이곳에 계속 남아 주시죠.","JPN":"他の容疑者さんは、こちらで待機してください。","ENG":"The remaining suspects are to stay here.","TWN":"其他嫌犯請留下。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"금방 돌아오지.","JPN":"すぐ戻る。","ENG":"I'll be back soon.","TWN":"我馬上回來。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 알겠어.","JPN":"わ、わかった。","ENG":"G-got it.","TWN":"嗯，知道了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…조심해서 다녀와.","JPN":"……気をつけてね。","ENG":"...Be careful.","TWN":"……路上小心。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네. 너무 걱정은 말게나.","JPN":"ありがとう。あまり心配するな。","ENG":"Thank you. Don't worry.","TWN":"謝謝。不用太擔心。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사태의 원인은 어느 정도까지 파악됐나?","JPN":"事態の原因はどこまで把握できたのだ？","ENG":"How much information have you gathered regarding the cause of the incident?","TWN":"有沒有找到事情發生的原因？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"용의자 신분으로 그런 질문을 하다니 뻔뻔하네.","JPN":"容疑者のくせにそんな質問をするなんて、図々しいな。","ENG":"How bold of you to ask that as a suspect yourself.","TWN":"你身為嫌犯還好意思問這個問題。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"진짜 용의자는 얼추 추려졌어.","JPN":"本物の容疑者はあらかた特定できた。","ENG":"We whittled down the list of suspects.","TWN":"真正的嫌犯已有大致輪廓了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 중 하나가 너무 뜻밖이라 몇 번이고 교차검증을 하다 조금 늦어진 거고.","JPN":"その中の一人があまりにも意外で、何度も交差検証をしていて少し遅くなったのだ。","ENG":"The process was delayed because one of them was so unexpected that we had to cross-check multiple times.","TWN":"其中一個因為太出乎意料，進行了多次交叉核對，所以才拖了這麼久。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 누구지?","JPN":"誰だったんだ？","ENG":"And who is that?","TWN":"到底是誰？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이 얘길 하려면 우선 리하르트가 사망 전에 무엇을 하고 있었냐에 초점을 맞춰야 해.","JPN":"この話の前に、まずはリヒャルトが死亡前に何をしていたのかに焦点を当てる必要がある。","ENG":"For context, we first have to focus on what Richard was doing before he died.","TWN":"首先要從理查在死亡前做了什麼事講起。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"얼마 전 육익 멤버 퍼스트윙이 체포됐어.","JPN":"この前、六翼のメンバーであるファーストウイングが逮捕された。","ENG":"Not too long ago, a member of Six Wings called Firstwing was arrested.","TWN":"前幾天，前六翼成員弗斯特薇被捕了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"육익에 내분이 있었고, 그 과정에서 퍼스트윙이 제압됐다더군.","JPN":"六翼で内輪もめが起こり、その過程でファーストウイングが制圧されたらしい。","ENG":"There was an internal conflict within Six Wings, and Firstwing was taken down during that process.","TWN":"六翼發生了內訌，弗斯特薇在此過程中被制伏了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내분이라… 하지만 시기상 우리가 알고 있는 둘은 개입이 불가능했을 텐데.","JPN":"内輪もめか……だが、その時期に私たちが知っているあの二人は介入できなかったはずだ。","ENG":"An internal conflict... But considering when it happened, the two members we know couldn't have intervened.","TWN":"內訌……但我們所知的兩個人因為時間關係並不能介入此事才對。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래서 우린 관리국에서 파악하지 못한 제3의 인물이 있을 거라 판단했어.","JPN":"そこで私たちは管理局で把握できなかった第三の人物がいると判断した。","ENG":"Which is why we deduced that there must have been a third member the Administration didn't know about.","TWN":"所以我們認為肯定還有管理局尚未掌握的第三者。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트는 그 인물에 대해 조사했고, 당신 증언대로라면 리하르트가 당신을 부른 건 그 인물에 대해 알려주기 위해서였겠지.","JPN":"リヒャルトはその人物について調査していた。リヒャルトがあなたを呼んだのは、その人物について教えるためだったんだろう。","ENG":"Richard started investigating this person, and based on your statement, he wanted to inform you about that person.","TWN":"理查對這個人展開了調查，根據你的證詞，他把你叫來應該就是為了把關於那個人的資訊告訴你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정보를 차단하려고… 리하르트를 입막음한 건가.","JPN":"情報を遮断するために……リヒャルトの口止めをしたのか。","ENG":"So... Richard was silenced to stop the information from spreading.","TWN":"是為了避免資訊洩露……才選擇殺人滅口嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"범인은 그걸로 충분할 거라 생각했겠지.","JPN":"犯人はそれで十分だと思ったのだろうな。","ENG":"The culprit probably thought that was enough.","TWN":"兇手可能覺得這樣就足夠了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 리하르트는 그렇게 허술하지 않았어. 자신이 수집한 자료들을 모두 인공위성의 백업데이터로 남겨뒀거든.","JPN":"だが、リヒャルトはそうお粗末ではなかった。自分が収集した資料を、全部人工衛星のバックアップデータとして残しておいたんだ。","ENG":"But Richard wasn't that careless. He left all the information he had gathered as backup data on a satellite.","TWN":"但理查並沒有這麼馬虎，他把所有資料都留在了衛星上作為備份。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"확인해봐.","JPN":"これを見てみろ。","ENG":"Check this.","TWN":"快看看。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"육익 멤버들이 사건을 벌이고 자취를 감춘 현장엔 모두 종이가 한 장씩 있었군.","JPN":"六翼メンバーが事件を起こした現場には、どこも1枚の紙が残されていた。","ENG":"A piece of paper was found at every place the Six Wings members caused trouble and disappeared.","TWN":"六翼成員引發事件後隱藏蹤跡的地點都有一張紙。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래. 관리국도 처음엔 우연이라 생각했지만, 두번째 종이가 발견됐을 때부턴 그 연관성에 대해 조사하기 시작했지.","JPN":"ああ。管理局も最初は偶然だと思っていたが、2枚目が発見されてからはその関連性について調査し始めた。","ENG":"Yeah. The Administration thought it was a coincidence at first, but it led to an investigation once the second piece of paper was found.","TWN":"是的。管理局起初認為這是巧合，但當第二張紙被發現後，他們開始研究其中的關聯。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"종이마다 뜬구름 잡는 소리들만 적혀 있었는데, 아무리 단서를 모아도 딱히 진전은 없었어.","JPN":"紙には訳のわからないことが書いてあったのだが、その内容を集めても大した進展はなかったのだ。","ENG":"Each piece of paper contained gibberish, and no amount of clues led them anywhere.","TWN":"每張紙上都寫滿了胡言亂語，無論我拼湊出多少線索都沒有任何進展。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러다가 어제 첫 방영된 아침 드라마 한 편에서 그 진실이 밝혀졌지.","JPN":"だが、昨日初放送された朝ドラでその真実が明らかになった。","ENG":"Until, the first episode of a soap opera was released yesterday.","TWN":"然而終於在昨天開播的晨間連續劇中發現了真相。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 단서들이 모두… 드라마 각본이었군.","JPN":"あの紙の内容はすべて……ドラマの脚本だったのだな。","ENG":"These clues are all... part of a script for a soap opera.","TWN":"這些線索都是……連續劇劇本。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드에서 투자하는 미디어 산업의 비중이 큰 만큼, 이런 각본은 극비에 관리되고 있어.","JPN":"シャレードが投資するメディア産業の比重が大きい分、こういった脚本は極秘で管理されている。","ENG":"Charade spends a lot of money on the media industry, so scripts like this one are handled with the utmost care.","TWN":"鑒於查雷德投資的媒體產業比重龐大，這些劇本是絕對機密。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그런데 범인은 그걸 한참 전부터 현장에 뿌리고 다녔다는 거지.","JPN":"ところが、犯人はそれをずっと前から現場にばら撒いていたわけだ。","ENG":"But the culprit has been leaking these kinds of scripts for a long time.","TWN":"而兇手卻早就在現場留下了這些劇本。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"각본가와 주연 배우가 동일 인물인 건가?","JPN":"脚本家と主演の俳優が同一人物なのか？","ENG":"The writer and the leading actress are the same person?","TWN":"劇本作家和主演是同一個人？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래, 샤레이드의 대배우 스완.","JPN":"ああ、シャレードの大女優スワンだよ。","ENG":"Yeah. Swan, the legendary actress of Charade.","TWN":"是的，查雷德的著名演員史旺。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"돈과 명성이 곧 계급이 되는 샤레이드 사회에서 그녀의 지위는 많은 도움이 돼.","JPN":"お金と名声が階級になるシャレードの社会で、彼女の地位は大いに役立つ。","ENG":"Her position is very helpful in Charade's society, where money and fame mean everything.","TWN":"在金錢和名望構成階級的查雷德社會，她的地位會給她帶來很多幫助。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"원하는 정보를 얻는 것에도, 자기 과거를 숨기는 데에도 말이야.","JPN":"ほしい情報を得ること以外に、自分の過去を隠すことにもな。","ENG":"It's helpful in gathering information as well as hiding her own past.","TWN":"比如收集需要的情報，隱藏自己的過去。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"단서 자체가 그녀를 음해하려는 목적일 가능성도 있지 않나?","JPN":"だが脚本を使って彼女を陥れようとした可能性もあるのではないか？","ENG":"Isn't it possible that someone's trying to frame her using the script?","TWN":"有沒有可能這些線索單純只是為了毀壞她的名聲？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"항상 대외적으로 얼굴을 비추는 그녀라면 알리바이는 충분히 있을 텐데.","JPN":"いつも対外的に顔を出している彼女なら、アリバイは十分あるはずだが。","ENG":"She must have an alibi, since she attends various social events.","TWN":"像她這樣經常出現在公眾視線中的人一定有充分的不在場證明。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아, 당신은 여기 갇혀 있느라 몰랐겠네.","JPN":"あぁ、あなたはここに閉じ込められていたから知らないのか。","ENG":"Ah, you probably haven't heard since you were trapped here.","TWN":"喔，你一直被困在這裡，難怪不知道。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"스완은 건틀렛 경기가 끝나자마자 작품활동을 쉬겠다고 발표했어.","JPN":"スワンはガントレットの試合が終わってすぐ女優業を休むと発表した。","ENG":"Swan announced that she was going to take a break from work right after the Gauntlet match ended.","TWN":"史旺在聖鎧比賽結束之後就宣佈要進入休息期。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"본인이 직접 카메라 앞에 나서는 대신 매니저를 대리로 세워서 말이야.","JPN":"本人が直接カメラの前に出る代わりに、マネージャーが代理でな。","ENG":"And she didn't go on camera to announce it. It was her manager.","TWN":"她讓經紀人代替自己入鏡。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그리곤 사건 발생 시각으로부터 약 한 시간 뒤, 당일날 당당하게 여객기를 타고 로터스로 떠났더라고.","JPN":"そして事件発生からおよそ1時間後、堂々と飛行機に乗ってロータスへと旅立った。","ENG":"Approximately one hour after the incident, she took a plane to Lotus without even trying to hide it.","TWN":"事件發生約一小時後，她大搖大擺地坐飛機向洛德斯出發了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"로터스 공항에 검문을 요청했지만, 우리가 추격할 거란 걸 알았는지 이미 사라지고 없었어.","JPN":"ロータス空港に検問を要請したのだが、私たちが追跡すると予想していたのか、すでに姿はなかった。","ENG":"We asked Lotus Airport to do an inspection, but I guess she already knew we were going to come after her. She was already gone.","TWN":"我們要求洛德斯機場對其進行審問，但她似乎知道我們在追她，因此早就隱匿了行蹤。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀의 행동이 우연의 일치라 보기엔 어렵군.","JPN":"彼女の行動が偶然の一致であるとは考えにくいな。","ENG":"It's hard to believe it's all a coincidence.","TWN":"她的這一切行為很難說只是巧合。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 그리고 이상할 정도로 자신의 행적을 숨기지 않았지.","JPN":"ああ。それに、不自然なほど自分の足取りを隠そうとしなかった。","ENG":"Right, and she didn't even bother to cover her tracks.","TWN":"是的，而奇怪的是她並沒有隱藏自己的行蹤。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"꼭 자길 쫓아와 주길 바라는 것처럼.","JPN":"まるで、自分を追いかけろとでもいうように。","ENG":"It's as if she wants to be chased.","TWN":"好像她希望別人追蹤自己似的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…쫓을 생각인가?","JPN":"……追いかけるつもりなのか？","ENG":"...And are you going to chase her?","TWN":"……你要去追嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"쫓아야지.","JPN":"追いかけるよ。","ENG":"I have to.","TWN":"當然。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 어중이떠중이들을 다 모아가면서까지 일을 크게 벌일 생각은 없어.","JPN":"だが、烏合の衆を集めてまで大ごとにするつもりはない。","ENG":"But I'm not going to cause a commotion by gathering just anyone.","TWN":"不過不想派太多人力把事情鬧大。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"가장 믿을 수 있는 소수정예를 로터스로 보낼 예정이야.","JPN":"もっとも信頼できる人のみを集め、少数精鋭でロータスに送るつもりだ。","ENG":"I'm going to send a group of the most trustworthy people to Lotus.","TWN":"我要把最可靠的精銳派到洛德斯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋은 소식 기대하지.","JPN":"いい知らせを待つとしよう。","ENG":"I'll be looking forward to some good news.","TWN":"希望有好消息。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"남일처럼 말하고 자빠졌네.","JPN":"他人事のように話すのだな。","ENG":"Look at you, talking like it's none of your business.","TWN":"不要一副和你沒關係的口氣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 신세로는 내가 할 수 있는 일이 거의 없으니까.","JPN":"今私にできることはほとんどないのでね。","ENG":"Well, my hands are tied at the moment.","TWN":"但現在的我確實幫不上什麼忙。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전화기라도 있으면 도움을 줄 수 있을 것 같은데.","JPN":"電話でもあれば、役に立てるかもしれないが。","ENG":"I might be able to help if you can get me a phone.","TWN":"如果有電話，或許我還能給你一些幫助。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하아… 그러던지.","JPN":"はあ……勝手にしろ。","ENG":"*Sigh...* Fine.","TWN":"唉……隨便吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇지 않아도 당신 직원한테서 통화가 왔었어. 확인해봐.","JPN":"ちょうどあなたの職員から電話が来ていたから、確認するといい。","ENG":"You actually got a call from one of your employees. You should check it.","TWN":"你的員工確實有打電話來，你看看吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 처지에 자유롭게 통화를 해도 괜찮은 건가?","JPN":"私の立場で、自由に電話しても大丈夫なのか？","ENG":"Am I allowed to call freely, given my current status?","TWN":"我可以自由自在地打電話嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"됐어. 당신과 당신 직원들 알리바이는 내가 확보했으니까.","JPN":"構わない。あなたと職員たちのアリバイは私が確保したのだから。","ENG":"It's fine. I confirmed you and your employees' alibis.","TWN":"無所謂了。我已經確定了你和你員工的不在場證明。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"통화내용은 전부 감청되고 있으니 알아두고.","JPN":"だが通話の内容はすべて聞かれているから、覚えておけ。","ENG":"You should know that all your calls will be monitored.","TWN":"別忘了，你的通話內容都會被監控。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮네. 자네와의 신뢰를 생각해서라도, 더 이상 숨기는 게 없는 편이 좋으니.","JPN":"大丈夫さ。君との関係を考えると、隠し事はないほうがいいだろうからな。","ENG":"All good. It would be better to keep everything in the open to gain your trust.","TWN":"沒關係，為了我們彼此的信任，我不會再隱瞞什麼。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전화 받았네.","JPN":"もしもし。","ENG":"Yes?","TWN":"接通了呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 간만이네요. 사장님.","JPN":"あ、社長。お久しぶりです。","ENG":"Oh, it's been a while, Boss.","TWN":"啊，好久不見，老闆。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국 사람들에게 붙잡혀서 호텔방에 갇혀 계신다길래 걱정했습니다.","JPN":"管理局に捕まって、ホテルの部屋に閉じ込められていると聞いて心配したんですよ。","ENG":"I was worried when I heard that you were locked up in a hotel room by the Administration.","TWN":"我聽說老闆被管理局扣留關在飯店房間裡，我一直很擔心呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"거긴 식사는 잘 나오던가요?","JPN":"ご飯はちゃんと出ていますか？","ENG":"How's the food there?","TWN":"那裡的伙食還可以嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드 최고의 호텔이니 두 말할 것도 없지.","JPN":"当然さ。ここはシャレード最高のホテルなのだから。","ENG":"It's the best hotel in Charade, so, it's amazing.","TWN":"當然了，畢竟是查雷德最高級的飯店。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"덕분에 미나 양도 비싼 스테이크 맛에 눈을 떴다네.","JPN":"おかげでミナ君が高級ステーキの味に目覚めてしまったよ。","ENG":"Now, even Mina has a taste for expensive steak.","TWN":"多虧如此，米娜也嚐到了高級牛排的味道。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아하하, 그건 또 새로운 걱정거리가 되겠네요.","JPN":"あはは、それはまた新しい心配事ができましたね。","ENG":"Ah hah hah, one more concern to add to the list.","TWN":"哈哈哈，她的胃口被養大啦。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 별일 없었나?","JPN":"君は大丈夫なのかい？","ENG":"How are things on your side?","TWN":"你還好嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"끼니라면 부사장님께서 주신 카드로 잘 해결하고 있습니다.","JPN":"食事なら副社長から貰ったカードでちゃんと食べてます。","ENG":"Well, my meals are taken care of with the card I got from the Vice President.","TWN":"老闆是問三餐的部分嗎？我有用副總給我的卡吃飯。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"밥값 리미트가 하이웨이 샌드위치 가격을 아슬아슬하게 웃돌긴 하지만요.","JPN":"食費のリミットがハイウェイサンドイッチ一つ買える程度ですけどね。","ENG":"Even though the meals can't exceed the price of an average Highway sandwich.","TWN":"雖然說餐費上限只比超商三明治高出一些些。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 이해해주게. 사옥이 그렇게 된 뒤로 사정이 여의치 않아서 말이야.","JPN":"理解してくれたまえ。会社がああなってから、懐の事情がよろしくないのだ。","ENG":"I hope you understand. Things have been difficult after what happened with our office.","TWN":"希望你能理解。辦公室出事後，情況就一直不太好。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"농담입니다. 저야 이 정도로도 감지덕지죠.","JPN":"冗談です。僕には十分すぎるくらいですよ。","ENG":"I'm only joking. I'm more than grateful for this.","TWN":"開個玩笑。我已經很滿足了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 당분간 돌아가기가 힘들어져서 사장님께는 죄송스럽게 됐어요.","JPN":"でも、しばらく戻れそうにないので、社長には申し訳ありません。","ENG":"But I'm sorry. I'm not going to be able to return for a while.","TWN":"但我暫時應該很難回去，對老闆很不好意思。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"급한 용무가 생긴 모양이군.","JPN":"急用ができたようだな。","ENG":"Seems like something urgent came up.","TWN":"看來你有急事。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네, 뒷담화를 좀 하자면 (전)펜릴 선배님의 동료분께서 재를 많이 뿌려 놓고 가셨더라고요.","JPN":"はい、少し愚痴らせてもらいますと、元フェンリル先輩の仲間が破天荒なもので。","ENG":"Yes. I wouldn't want to gossip, but the \\"former\\" Fenrir member's colleague has left quite a mess behind her.","TWN":"是的，(前)芬里爾前輩的同伴闖出了不少禍。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님이 돌아오시기 전에 급한 일 몇 가지는 제가 수습하게 될 것 같습니다.","JPN":"師匠がお戻りになる前に、僕が何件か後始末をすることになりそうです。","ENG":"It looks like I'll have to take care of a few urgent matters before Master returns.","TWN":"在師父回來之前，一些要緊的事情只能先由我來處理了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 하게.","JPN":"そうしたまえ。","ENG":"Very well.","TWN":"那就這樣吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"허락해 주셔서 감사합니다.","JPN":"許可していただき、ありがとうございます。","ENG":"Thank you for your permission.","TWN":"謝謝老闆。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"도움을 주지 못해 미안할 따름일세.","JPN":"助けになれなくてすまないね。","ENG":"I'm just sorry I can't provide any assistance.","TWN":"很抱歉幫不上老闆的忙。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 미나 양에게도 조금 늦을 거라고 안부 전해주세요.","JPN":"はは、ミナさんにも少し遅くなるって伝えてください。","ENG":"Hah hah, and please send word to Mina that I'll be a bit late.","TWN":"哈哈，也請替我告訴米娜我晚些才能回去。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 그리고 한 가지 더…","JPN":"あ、それからもう一つ……","ENG":"Oh, and one more thing...","TWN":"喔，還有一件事……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…스완이란 사람을 조심하라고 했다고? 선배가?","JPN":"……スワンって人に気をつけろって？　先輩が言ってた？","ENG":"...\\"Beware of someone called Swan?\\" That's what he said?","TWN":"……前輩說要小心一個叫史旺的人？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 그녀가 다음으로 노리는 게 우리 중 한 명일 수도 있을 거라고 하더군.","JPN":"そうだ。彼女が次に狙うのが私たち二人のうち、どちらかかもしれないと言っていた。","ENG":"Yes. He said she might be coming for one of us next.","TWN":"是的。說她的下一個目標很可能是我們當中的一個。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"TV만 켜면 나오던 지상파의 유명인사가 실은 육익이었던 데다 탈주한 멤버라니… 듣고도 이게 무슨 소리인가 싶네.","JPN":"いつもテレビで見てる有名人が六翼で、しかも脱走したメンバーだったなんて……信じられないな。","ENG":"The celebrity that was on every channel was actually a Six Wings member who is on the run... That sounds even more ridiculous when you say it out loud.","TWN":"每次打開電視都會看到的電視台名人其實是一名在逃的六翼成員……我還是不敢相信。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님은 어떻게 생각해? 선배 말처럼 그 사람이 정말 우릴 찾아올까?","JPN":"社長はどう思う？　先輩の言うとおり、あの人が本当に私たちのことを訪ねて来るかな？","ENG":"What do you think, Boss? Do you think she'll really come for us?","TWN":"老闆是怎麼想的？ 她真的會像前輩說的那樣來找我們嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금으로선 확신을 못하겠군.","JPN":"今はまだ確信できぬな。","ENG":"Nothing's for certain at the moment.","TWN":"我現在也不確定。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나도 그자에 관한 정보라면 흔히 알려진 커리어나 가십거리 외엔 없으니까.","JPN":"私も彼女についての情報は、よく知られているキャリアやゴシップしかない。","ENG":"I know about her general career or gossip, but nothing else.","TWN":"我對她的認識除了她的作品和八卦之外，幾乎是一無所知。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 마지막 행적이 로터스였다면 당장 이곳으로 올 것 같진 않아.","JPN":"だが、最後の目的地がロータスならすぐにこちらに向かうとは思えん。","ENG":"That being said, I don't think she'd come here anytime soon if her last destination was Lotus.","TWN":"但如果她最後出現的地點是洛德斯，我想應該不會馬上來這裡。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"으음… 뭔가 잘 이어지질 않네.","JPN":"うーん……なんかあんまり繋がらないな。","ENG":"Hmm… It doesn't make any sense.","TWN":"嗯……還是有些想不通。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리국 사람인 리하르트 씨를 살해했다면 보통은 관리국의 수사망에서 최대한 멀어지려 할 텐데, 로터스도 결국엔 관리국의 손 안에 있는 곳이잖아.","JPN":"管理局の人間であるリヒャルトさんを殺害したなら、普通は管理局の捜査網を避けようとするのに、ロータスだって結局は管理局の管理下だろ？","ENG":"If you had killed Richard, who's a part of the Administration, you'd want to get as far as possible from the Administration's reach. But Lotus is still within the Administration's network.","TWN":"如果是管理局的人謀殺了理查，通常會儘量遠離管理局的搜索網，但洛德斯明明也屬於管理局管轄範圍。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮은 지적이군.","JPN":"いい指摘だな。","ENG":"Good point.","TWN":"說的有道理。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그거라면 한 두 가지 짚이는 것은 있네만…","JPN":"それなら一つ二つ、心当たりがあるのだが……","ENG":"I do have a couple of guesses as to why...","TWN":"對於這一點我有幾個想法……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이건… 침식경보?","JPN":"これは……侵食警報？","ENG":"A... Corruption alert?","TWN":"這是……侵蝕警報？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};